## Code Example

```javascript
// Data models
class TenantBudget {
  constructor(tenantId, dailyBudget, tokensUsed = 0, lastReset = new Date()) {
    this.tenantId = tenantId;
    this.dailyBudget = dailyBudget;
    this.tokensUsed = tokensUsed;
    this.lastReset = lastReset;
  }
}

class RoutingDecision {
  constructor(modelVersion, promptTemplate = null, estimatedCost) {
    this.modelVersion = modelVersion;
    this.promptTemplate = promptTemplate;
    this.estimatedCost = estimatedCost;
  }
}

// Router implementation
class CostAwareRouter {
  route(tenantBudget, tokenCount, priority = 'normal') {
    const estimatedCost = this.calculateCost(tokenCount);
    const remainingBudget = tenantBudget.dailyBudget - tenantBudget.tokensUsed;

    let modelVersion;
    if (remainingBudget < estimatedCost * 2) {
      modelVersion = 'lite';
    } else if (priority === 'high' && remainingBudget >= estimatedCost * 5) {
      modelVersion = 'premium';
    } else {
      modelVersion = 'standard';
    }

    return new RoutingDecision(modelVersion, null, estimatedCost);
  }

  calculateCost(tokenCount) {
    return tokenCount * 0.0005; // $0.0005 per token
  }
}
```

This implementation demonstrates the core routing logic while maintaining simplicity for beginner-friendly deployment in enterprise environments.

