function sanitizePrompt(tenantPolicy, prompt) {
  let redacted = prompt;
  for (const r of tenantPolicy.redactRegexes) {
    redacted = redacted.replace(new RegExp(r, 'g'), '[REDACTED]');
  }
  tenantPolicy.redactFields.forEach(f => {
    const re = new RegExp(`"${f}"\s*:\s*"[^"]*"`, 'g');
    redacted = redacted.replace(re, `"${f}":"[REDACTED]"`);
  });
  return redacted;
}
```

