// Lightweight per-tenant circuit breaker skeleton
class CircuitBreaker {
  constructor(threshold=5, windowMs=60000) {
    this.threshold = threshold; this.windowMs = windowMs;
    this.failures = {}; // tenantId -> [timestamps]
  }
  recordFailure(tid){
    const now = Date.now();
    this.failures[tid] = (this.failures[tid]||[]).concat(now);
  }
  isOpen(tid){
    const now = Date.now();
    const arr = (this.failures[tid]||[]).filter(t=>now-t<=this.windowMs);
    return arr.length >= this.threshold;
  }
}
```

