```javascript
function route(prompt, tenantPolicy, region) {
  // Step 1: Check if policy engine is available
  if (!tenantPolicy) {
    return { target: 'default-path', reason: 'no-policy' };
  }

  // Step 2: Validate region compliance
  if (!tenantPolicy.allowedRegions.includes(region)) {
    return { target: 'default-path', reason: 'region-violation' };
  }

  // Step 3: Determine routing based on privacy posture
  if (!tenantPolicy.allowSharedModel) {
    return { target: 'tenant-sandbox', model: tenantPolicy.dedicatedModel };
