## Code Example
```go
// Hash chain verification with caching
func verifyProvenance(tenantID string, fromSeq, toSeq uint64) (bool, error) {
    // Check cache first for sub-50ms latency
    if result := cache.Get(tenantID, fromSeq, toSeq); result != nil {
        return result.valid, nil
    }

    // Batch fetch from distributed log
    records, err := logStore.FetchRange(tenantID, fromSeq, toSeq)
    if err != nil {
        return false, err
    }

    // Verify hash chain sequentially
    prevHash := records[0].PrevHash
    for _, record := range records {
        computed := sha256(prevHash + record.Payload)
        if computed != record.Hash {
            return false, nil
        }
        prevHash = record.Hash
    }

    // Cache result for future queries
    cache.Set(tenantID, fromSeq, toSeq, true)
    return true, nil
}
```

