// Minimal per-tenant token bucket (conceptual)
class TokenBucket {
  constructor(rate, capacity) {
    this.rate = rate; this.capacity = capacity; this.tokens = capacity; this.last = Date.now();
  }
  refill() {
    const now = Date.now();
    const add = (now - this.last) * this.rate / 1000;
    this.tokens = Math.min(this.capacity, this.tokens + add);
    this.last = now;
  }
  consume(n = 1) {
